int setparams(int* params, int n) {
	int i; 

	for (i = 0; i < n-13-25-10; i++)
		v[i] = params[i];

	for (i = 0; i < 13; i++) {
		ungroundedpenalty[i] = params[arraystart + i];
	}

	for (i = 0; i < 25; i++) {
		tmod[i] = params[arraystart + 13  + i];
	}

	for (i = 0; i < 10; i++) {
		kingmobility[i] = params[arraystart + 13 + 25 + i];
	}

	for (i = 0; i < 32; i++) {
		king_pst[i] = params[arraystart + 13 + 25 + 10 + i];
	}

	return 0; 
}


int getparams(int* params, int* n) {
	int i; 

	// copy br, ungrounded, tmod, kingmobility
	for (i = 0; i < 13; i++)
		v[arraystart + i] = ungroundedpenalty[i];

	for (i = 0; i < 25; i++)
		v[arraystart + i + 13] = tmod[i];

	for (i = 0; i < 10; i++)
		v[arraystart + i + 13 + 25] = kingmobility[i]; 

	for (i = 0; i < 32; i++)
		v[arraystart + i + 13 + 25 + 10] = king_pst[i]; 

	// then return all parameters
	*n = (arraystart + 13 + 25 + 10 + 32);
	for (i = 0; i < (*n); i++)
		params[i] = v[i]; 

	// normal params up to arraystart, 13 more for ungrounded, 256 for back rank, 25 for tmod, 10 for king mobility
	return 0; 
}

