	int indices_create() {
		int mult[12];

		//int totalindex;
		// create multipliers for bits (12 squares, with base 3)
		mult[0] = 1;
		for (int i = 1; i < 12; i++)
			mult[i] = mult[i - 1] * 3;


		// create index for a 12-bit pattern
		for (int i = 0; i < 4096; i++) {
			index[i] = 0;
			for (int j = 0; j < 12; j++) {
				if (i & (1 << j))
					index[i] += mult[j];
			}
		}


		/*for (int i = 0; i < MAX_PATTERN; i++) {
			// i is a number between 0 and 3^12, describing the pattern of the last 3 ranks 
			// for the case that there is no opponent king on the 2nd or 3rd rank
			indexnum[i] = 0;
		}*/

		// now for the king index
		mult[0] = 1;
		for (int i = 1; i < 8; i++)
			mult[i] = mult[i - 1] * 5;


		// create index for a 8-bit pattern
		for (int i = 0; i < 256; i++) {
			indexk[i] = 0;
			for (int j = 0; j < 8; j++) {
				if (i & (1 << j))
					indexk[i] += mult[j];
			}
		}

		return 1;
	}

#endif

int updateeval(void) {
	// updates the eval once new parameters have been set
	initializematerial(materialeval);
	initializebackrank(blackbackrankeval, whitebackrankeval, blackbackrankpower, whitebackrankpower);

	for (int i = 0; i < BRNUM; i++) {
		blackbackrankeval[i] = backrank[i];
#ifdef BR4
		whitebackrankeval[i] = backrank[reverse16(i)];
#else
		whitebackrankeval[i] = backrank[reverse12(i)];
#endif
	}

	return 1;
}

